#!/usr/bin/env python3
# -*- coding: utf-8 -*-
import pymongo
from pymongo import MongoClient

# MongoDB 配置
MONGO_CONFIG = {
    "host": "10.34.137.87",
    "port": 37018,
    "username": "nodeDayOpsWide_r",
    "password": "pRkuawfIRKXkRQu1nhTLYhjF96QpAyXXYou",
    "auth_db": "jarvis",
    "db": "jarvis",
    "collection": "nodeDayOpsWide",
}

# 连接 MongoDB
print("=== 统计 MongoDB 中 idcId 不为空的数据量 ===\n")
mongo_client = MongoClient(
    host=MONGO_CONFIG["host"],
    port=MONGO_CONFIG["port"],
    username=MONGO_CONFIG["username"],
    password=MONGO_CONFIG["password"],
    authSource=MONGO_CONFIG["auth_db"]
)
mongo_db = mongo_client[MONGO_CONFIG["db"]]
collection = mongo_db[MONGO_CONFIG["collection"]]

# 统计 idcId 不为空且不是空字符串的数量
query = {
    "idcId": {
        "$exists": True,
        "$ne": None,
        "$nin": [""]
    }
}
non_null_count = collection.count_documents(query)
total_count = collection.count_documents({})

print(f"总记录数: {total_count:,}")
print(f"idcId 不为空: {non_null_count:,}")
print(f"占比: {non_null_count*100.0/total_count:.2f}%")

# 按天统计
print("\n=== 按天统计 idcId 不为空的数据量 ===")
pipeline = [
    {
        "$match": query
    },
    {
        "$group": {
            "_id": "$day",
            "count": { "$sum": 1 }
        }
    },
    { "$sort": { "_id": 1 } }
]

result = collection.aggregate(pipeline)
print("\n日期         | idcId 不为空记录数")
print("--------------|-------------------")
for doc in result:
    print(f"{doc['_id']:<12} | {doc['count']:,}")

mongo_client.close()

